import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

function Cadastro() {
  const navigate = useNavigate();
  
  // Estado para armazenar os dados do formulário
  const [formData, setFormData] = useState({
    nome: '',
    email: '',
    telefone: '',
    outroDado: ''
  });

  // useEffect para carregar os dados salvos no localStorage após o login
  useEffect(() => {
    const savedUser = JSON.parse(localStorage.getItem('user'));
    if (savedUser) {
      setFormData(prev => ({
        ...prev,
        nome: savedUser.name, // Pré-preenche o nome vindo do Google
        email: savedUser.email // Pré-preenche o e-mail vindo do Google
      }));
    }
  }, []);

  const handleSubmit = (e) => {
    e.preventDefault();
    
    // Gera o objeto JSON com os dados do usuário conforme o Requisito 3
    const jsonDados = JSON.stringify(formData, null, 2);
    
    // Exibe o JSON no console para validação
    console.log("Objeto JSON Gerado:", jsonDados);
    
    alert("Cadastro finalizado! O JSON foi gerado no console (F12).");
  };

  return (
    <div style={{ padding: '20px', maxWidth: '500px', margin: '0 auto' }}>
      <h2>Cadastro de Usuário</h2>
      <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
        
        <label>Nome:</label>
        <input 
          type="text" 
          value={formData.nome} 
          readOnly // Campo bloqueado pois vem do Google
          style={{ backgroundColor: '#f0f0f0' }}
        />

        <label>E-mail:</label>
        <input 
          type="email" 
          value={formData.email} 
          readOnly // Campo bloqueado pois vem do Google
          style={{ backgroundColor: '#f0f0f0' }}
        />

        <label>Telefone (Opcional):</label>
        <input 
          type="tel" 
          placeholder="(00) 00000-0000"
          value={formData.telefone}
          onChange={(e) => setFormData({...formData, telefone: e.target.value})}
        />

        <label>Outros Dados:</label>
        <textarea 
          placeholder="Informações adicionais..."
          value={formData.outroDado}
          onChange={(e) => setFormData({...formData, outroDado: e.target.value})}
        />

        <button type="submit" style={{ padding: '10px', backgroundColor: '#4CAF50', color: 'white', cursor: 'pointer' }}>
          Finalizar Cadastro e Gerar JSON
        </button>
      </form>

      <button onClick={() => navigate('/')} style={{ marginTop: '20px' }}>
        Sair / Voltar para Home
      </button>
    </div>
  );
}

export default Cadastro;
